import { useEffect, useMemo, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { Modal } from "@/components/orderly/Modal";
import { OdsToggle } from "@/components/orderly/OdsToggle";
import { Plus, Trash2, Eye, Trophy } from "lucide-react";
import { useTranslation } from "@/i18n";
import { signedAdminRequest } from "@/utils/adminKeyAuth";
import { buildQueryString, orderlyApi } from "@/utils/api";
import { useBrokerInfo } from "@/components/provider/BrokerInfoProvider";
import { toast } from "@/hooks/use-toast";
import {
  fetchDexCreatorDexStatus,
  updateDexCreatorDexConfig,
} from "@/services/orderly";
import { walletGetItem } from "@/utils/storage";

type PointCampaign = {
  stage_id: number;
  epoch_period: number;
  start_time: number;
  end_time: number;
  status: string;
  stage_name: string;
  stage_description: string;
  is_continuous: boolean;
};

type PointCampaignDetail = {
  stage_id: number;
  epoch_period: number;
  stage_name: string;
  stage_description: string;
  start_date: string;
  end_date: string;
  volume_boost: number;
  pnl_boost: number;
  l1_referral_boost: number;
  l2_referral_boost: number;
};

type ModalMode = "create" | "view";

function isRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value && typeof value === "object");
}

function extractRows<T>(payload: unknown): T[] {
  if (Array.isArray(payload)) return payload as T[];
  if (isRecord(payload)) {
    if (Array.isArray(payload.rows)) return payload.rows as T[];
    if (isRecord(payload.data)) {
      if (Array.isArray((payload.data as Record<string, unknown>).rows))
        return (payload.data as Record<string, unknown>).rows as T[];
      if (Array.isArray(payload.data)) return payload.data as T[];
    }
  }
  return [];
}

function endpoint(path: string, params?: Record<string, unknown>) {
  return `${path}${buildQueryString(params)}`;
}

async function adminGet<T>(path: string, params?: Record<string, unknown>) {
  return signedAdminRequest<T>({ endpoint: endpoint(path, params) });
}

async function adminPost<T>(path: string, data: Record<string, unknown>) {
  return signedAdminRequest<T>({ endpoint: path, method: "POST", data });
}

async function adminDelete<T>(path: string, params?: Record<string, unknown>) {
  return signedAdminRequest<T>({
    endpoint: endpoint(path, params),
    method: "DELETE",
  });
}

async function publicGet<T>(path: string, params?: Record<string, unknown>) {
  return orderlyApi<T>({ endpoint: endpoint(path, params), token: null });
}

function errorMessage(error: unknown, fallback: string) {
  if (error instanceof Error) return error.message || fallback;
  return fallback;
}

function getStatusLabel(status: string): "ongoing" | "readyToGo" | "ended" {
  if (status === "active") return "ongoing";
  if (status === "pending") return "readyToGo";
  return "ended";
}

function formatDateFromTimestamp(ts: number): string {
  const d = new Date(ts * 1000);
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}`;
}

export default function PointsPage() {
  const { t } = useTranslation();
  const { brokerId } = useBrokerInfo();

  const [pointsEnabled, setPointsEnabled] = useState(false);
  const [campaigns, setCampaigns] = useState<PointCampaign[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [modalOpen, setModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>("create");
  const [selectedCampaign, setSelectedCampaign] =
    useState<PointCampaign | null>(null);
  const [submitting, setSubmitting] = useState(false);

  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [tradingVolumeBoost, setTradingVolumeBoost] = useState("0.1");
  const [pnlBoost, setPnlBoost] = useState("1");
  const [l1ReferralRate, setL1ReferralRate] = useState("10");
  const [l2ReferralRate, setL2ReferralRate] = useState("5");
  const [errors, setErrors] = useState<Record<string, string>>({});

  const [refreshKey, setRefreshKey] = useState(0);

  useEffect(() => {
    let cancelled = false;
    void (async () => {
      setLoading(true);
      setError("");
      try {
        const dexStatus = await fetchDexCreatorDexStatus();
        if (cancelled) return;
        setPointsEnabled(Boolean(dexStatus?.enableCampaigns));
      } catch {
        if (!cancelled) setPointsEnabled(false);
      }

      if (!brokerId) {
        if (!cancelled) {
          setLoading(false);
          setCampaigns([]);
        }
        return;
      }

      try {
        const payload = await publicGet<unknown>("/v1/public/points/stages", {
          broker_id: brokerId,
        });
        if (cancelled) return;
        const rows = extractRows<PointCampaign>(payload);
        rows.sort((a, b) => b.start_time - a.start_time);
        setCampaigns(rows);
      } catch (err) {
        if (!cancelled) {
          setCampaigns([]);
          setError(errorMessage(err, "Failed to load campaigns"));
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [brokerId, refreshKey]);

  const nextStage = useMemo(() => {
    if (campaigns.length === 0) return 1;
    return Math.max(...campaigns.map(c => c.stage_id)) + 1;
  }, [campaigns]);

  function refresh() {
    setRefreshKey(k => k + 1);
  }

  async function handleTogglePoints(enabled: boolean) {
    const dexId =
      typeof window !== "undefined" ? walletGetItem("orderlyDexId") : null;
    if (!dexId) {
      toast({
        title: "DEX ID not found. Please reload the page.",
        variant: "destructive",
      });
      return;
    }
    try {
      const formData = new FormData();
      formData.append("enableCampaigns", String(enabled));
      await updateDexCreatorDexConfig(dexId, formData);
      setPointsEnabled(enabled);
      if (enabled) {
        toast({ title: t("points.enabled") });
      }
    } catch (err) {
      toast({
        title: errorMessage(err, "Failed to toggle points system"),
        variant: "destructive",
      });
    }
  }

  function resetForm() {
    setTitle("");
    setDescription("");
    setStartDate("");
    setEndDate("");
    setTradingVolumeBoost("0.1");
    setPnlBoost("1");
    setL1ReferralRate("10");
    setL2ReferralRate("5");
    setErrors({});
  }

  function openCreateModal() {
    setModalMode("create");
    setSelectedCampaign(null);
    resetForm();
    setModalOpen(true);
  }

  function openViewModal(campaign: PointCampaign) {
    setModalMode("view");
    setSelectedCampaign(campaign);
    setTitle(campaign.stage_name);
    setDescription(campaign.stage_description);
    setStartDate(formatDateFromTimestamp(campaign.start_time));
    setEndDate(formatDateFromTimestamp(campaign.end_time));
    setTradingVolumeBoost("");
    setPnlBoost("");
    setL1ReferralRate("");
    setL2ReferralRate("");
    setErrors({});
    setModalOpen(true);

    adminGet<unknown>("/v1/admin/points/stage", {
      stage_id: campaign.stage_id,
    })
      .then(payload => {
        const root = isRecord(payload) ? payload : {};
        const detail = (isRecord(root.data)
          ? root.data
          : root) as unknown as PointCampaignDetail;
        if (detail.volume_boost !== undefined)
          setTradingVolumeBoost(String(detail.volume_boost));
        if (detail.pnl_boost !== undefined)
          setPnlBoost(String(detail.pnl_boost));
        if (detail.l1_referral_boost !== undefined)
          setL1ReferralRate(String(detail.l1_referral_boost));
        if (detail.l2_referral_boost !== undefined)
          setL2ReferralRate(String(detail.l2_referral_boost));
      })
      .catch(() => {});
  }

  function validateForm(): boolean {
    const newErrors: Record<string, string> = {};
    if (!title.trim()) {
      newErrors.title = "Campaign title is required";
    }
    if (!startDate) {
      newErrors.startDate = "Start date is required";
    }
    if (!endDate) {
      newErrors.endDate = "End date is required";
    }
    if (startDate && endDate) {
      if (new Date(endDate) <= new Date(startDate)) {
        newErrors.endDate = "End date must be after start date";
      }
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }

  async function handleSaveCampaign() {
    if (modalMode === "view") {
      setModalOpen(false);
      return;
    }
    if (!validateForm()) return;

    setSubmitting(true);
    try {
      await adminPost("/v1/admin/points/stage", {
        stage_name: title.trim(),
        stage_description: description.trim(),
        start_date: startDate,
        end_date: endDate,
        is_continuous: false,
        volume_boost: Number(tradingVolumeBoost) || 0.1,
        pnl_boost: Number(pnlBoost) || 1,
        l1_referral_boost: Number(l1ReferralRate) || 10,
        l2_referral_boost: Number(l2ReferralRate) || 5,
      });
      setModalOpen(false);
      resetForm();
      toast({ title: t("points.campaignCreated") });
      refresh();
    } catch (err) {
      toast({
        title: errorMessage(err, "Failed to save campaign"),
        variant: "destructive",
      });
    } finally {
      setSubmitting(false);
    }
  }

  async function handleDeleteCampaign(stageId: number) {
    if (!window.confirm("Delete this campaign?")) return;
    setSubmitting(true);
    try {
      await adminDelete("/v1/admin/points/stage", { stage_id: stageId });
      toast({ title: "Campaign deleted" });
      refresh();
    } catch (err) {
      toast({
        title: errorMessage(err, "Failed to delete campaign"),
        variant: "destructive",
      });
    } finally {
      setSubmitting(false);
    }
  }

  const isReadOnly = modalMode === "view";

  return (
    <PageShell pageTitle={t("points.title")}>
      <div className="space-y-6">
        <div className="mb-6 rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <h3 className="text-lg font-medium text-(--fg-primary)">
                {t("points.enablePointSystem")}
              </h3>
              <p className="mt-1 text-sm text-(--fg-secondary)">
                {t("points.enableDescription")}
              </p>
            </div>
            <OdsToggle
              checked={pointsEnabled}
              onCheckedChange={handleTogglePoints}
              aria-label={t("points.enablePointSystem")}
            />
          </div>
        </div>

        <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
          <div className="mb-4 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Trophy className="h-5 w-5 text-(--fg-brand)" />
              <h3 className="text-lg font-medium text-(--fg-primary)">
                {t("points.pointCampaigns")}
              </h3>
            </div>
            <button
              type="button"
              onClick={openCreateModal}
              className="inline-flex items-center gap-2 rounded-full px-4 py-2 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90"
              style={{ background: "var(--bg-brand-grad)" }}
            >
              <Plus className="h-4 w-4" />
              {t("points.createCampaign")}
            </button>
          </div>

          {loading ? (
            <div className="flex items-center justify-center py-16">
              <div className="h-8 w-8 animate-spin rounded-full border-2 border-(--line-subtle) border-t-(--fg-brand)" />
            </div>
          ) : error ? (
            <div className="flex flex-col items-center justify-center py-16 text-center">
              <p className="text-sm text-(--fg-negative)">{error}</p>
              <button
                type="button"
                onClick={refresh}
                className="mt-3 text-sm font-medium text-(--fg-brand) hover:underline"
              >
                Retry
              </button>
            </div>
          ) : campaigns.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-16 text-center">
              <div className="mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-[rgba(188,135,255,0.08)]">
                <Trophy className="h-8 w-8 text-(--fg-secondary)" />
              </div>
              <p className="text-base font-medium text-(--fg-primary)">
                {t("points.noCampaigns")}
              </p>
              <p className="mt-1 max-w-xs text-sm text-(--fg-secondary)">
                {t("points.createFirstCampaign")}
              </p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead>
                  <tr className="border-b border-(--line-subtle) text-(--fg-secondary)">
                    <th className="pb-3 font-medium">{t("points.stage")}</th>
                    <th className="pb-3 font-medium">
                      {t("points.campaignTitle")}
                    </th>
                    <th className="pb-3 font-medium">
                      {t("points.startDate")}
                    </th>
                    <th className="pb-3 font-medium">{t("points.endDate")}</th>
                    <th className="pb-3 font-medium">{t("common.status")}</th>
                    <th className="pb-3 font-medium text-right">
                      {t("common.action")}
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {campaigns.map(campaign => {
                    const label = getStatusLabel(campaign.status);
                    const statusBadge =
                      label === "ongoing" ? (
                        <span className="inline-flex items-center rounded-full bg-[rgba(29,246,181,0.12)] px-2.5 py-0.5 text-xs font-medium text-[#1DF6B5]">
                          {t("points.ongoing")}
                        </span>
                      ) : label === "readyToGo" ? (
                        <span className="inline-flex items-center rounded-full bg-[rgba(217,171,82,0.12)] px-2.5 py-0.5 text-xs font-medium text-[#D9AB52]">
                          {t("points.readyToGo")}
                        </span>
                      ) : (
                        <span className="inline-flex items-center rounded-full bg-[rgba(255,255,255,0.08)] px-2.5 py-0.5 text-xs font-medium text-(--fg-secondary)">
                          {t("points.ended")}
                        </span>
                      );

                    return (
                      <tr
                        key={campaign.stage_id}
                        className="border-b border-(--line-subtle) last:border-b-0"
                      >
                        <td className="py-3 text-(--fg-primary)">
                          {campaign.stage_id}
                        </td>
                        <td className="py-3 text-(--fg-primary)">
                          {campaign.stage_name}
                        </td>
                        <td className="py-3 text-(--fg-secondary)">
                          {formatDateFromTimestamp(campaign.start_time)}
                        </td>
                        <td className="py-3 text-(--fg-secondary)">
                          {formatDateFromTimestamp(campaign.end_time)}
                        </td>
                        <td className="py-3">{statusBadge}</td>
                        <td className="py-3">
                          <div className="flex items-center justify-end gap-2">
                            <button
                              type="button"
                              onClick={() => openViewModal(campaign)}
                              className="inline-flex items-center gap-1 rounded-full border border-(--line-strong) bg-transparent px-3 py-1.5 text-xs font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
                            >
                              <Eye className="h-3.5 w-3.5" />
                              {t("common.view")}
                            </button>
                            <button
                              type="button"
                              onClick={() =>
                                handleDeleteCampaign(campaign.stage_id)
                              }
                              className="inline-flex h-8 w-8 items-center justify-center rounded-full border border-(--line-strong) bg-transparent text-(--fg-secondary) transition-colors hover:bg-(--bg-hover) hover:text-(--fg-primary)"
                              aria-label={t("common.delete")}
                            >
                              <Trash2 className="h-4 w-4" />
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      <Modal open={modalOpen} onClose={() => setModalOpen(false)}>
        <h3 className="mb-1 text-xl font-medium text-(--fg-primary)">
          {isReadOnly
            ? t("common.view") + " " + t("points.campaignTitle")
            : t("common.create") + " " + t("points.campaignTitle")}
        </h3>
        <p className="mb-5 text-sm text-(--fg-secondary)">
          {isReadOnly
            ? t("common.viewDetails")
            : t("points.createFirstCampaign")}
        </p>

        <div className="space-y-4">
          <div>
            <label className="mb-1.5 block text-sm text-(--fg-secondary)">
              {t("points.campaignTitle")}{" "}
              <span className="text-(--fg-negative)">*</span>
            </label>
            <input
              type="text"
              value={title}
              onChange={e => setTitle(e.target.value)}
              readOnly={isReadOnly}
              maxLength={40}
              placeholder="Enter campaign title"
              className={`w-full rounded-lg border px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors ${errors.title ? "border-(--line-negative)" : "border-(--line-subtle)"} ${isReadOnly ? "bg-(--bg-surface-secondary) text-(--fg-secondary)" : "bg-(--bg-input) focus:border-(--line-brand)"}`}
            />
            {errors.title && (
              <p className="mt-1 text-xs text-(--fg-negative)">
                {errors.title}
              </p>
            )}
            <p className="mt-1 text-right text-xs text-(--fg-placeholder)">
              {title.length}/40
            </p>
          </div>

          <div>
            <label className="mb-1.5 block text-sm text-(--fg-secondary)">
              {t("points.campaignDescription")}
            </label>
            <textarea
              value={description}
              onChange={e => setDescription(e.target.value)}
              readOnly={isReadOnly}
              maxLength={280}
              placeholder="Enter campaign description"
              rows={3}
              className={`w-full resize-none rounded-lg border px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors ${isReadOnly ? "border-(--line-subtle) bg-(--bg-surface-secondary) text-(--fg-secondary)" : "border-(--line-subtle) bg-(--bg-input) focus:border-(--line-brand)"}`}
            />
            <p className="mt-1 text-right text-xs text-(--fg-placeholder)">
              {description.length}/280
            </p>
          </div>

          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <div>
              <label className="mb-1.5 block text-sm text-(--fg-secondary)">
                {t("points.startDate")}{" "}
                <span className="text-(--fg-negative)">*</span>
              </label>
              <input
                type="date"
                value={startDate}
                onChange={e => setStartDate(e.target.value)}
                readOnly={isReadOnly}
                className={`w-full rounded-lg border px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors ${errors.startDate ? "border-(--line-negative)" : "border-(--line-subtle)"} ${isReadOnly ? "bg-(--bg-surface-secondary) text-(--fg-secondary)" : "bg-(--bg-input) focus:border-(--line-brand)"}`}
              />
              {errors.startDate && (
                <p className="mt-1 text-xs text-(--fg-negative)">
                  {errors.startDate}
                </p>
              )}
            </div>
            <div>
              <label className="mb-1.5 block text-sm text-(--fg-secondary)">
                {t("points.endDate")}{" "}
                <span className="text-(--fg-negative)">*</span>
              </label>
              <input
                type="date"
                value={endDate}
                onChange={e => setEndDate(e.target.value)}
                readOnly={isReadOnly}
                className={`w-full rounded-lg border px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors ${errors.endDate ? "border-(--line-negative)" : "border-(--line-subtle)"} ${isReadOnly ? "bg-(--bg-surface-secondary) text-(--fg-secondary)" : "bg-(--bg-input) focus:border-(--line-brand)"}`}
              />
              {errors.endDate && (
                <p className="mt-1 text-xs text-(--fg-negative)">
                  {errors.endDate}
                </p>
              )}
            </div>
          </div>

          <div>
            <label className="mb-1.5 block text-sm text-(--fg-secondary)">
              {t("points.stage")}
            </label>
            <input
              type="text"
              value={
                isReadOnly ? (selectedCampaign?.stage_id ?? "") : nextStage
              }
              readOnly
              className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-3 py-2 text-sm text-(--fg-secondary)"
            />
          </div>

          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <div>
              <label className="mb-1.5 block text-sm text-(--fg-secondary)">
                {t("points.tradingVolumeBoost")}
              </label>
              <input
                type="number"
                value={tradingVolumeBoost}
                onChange={e => setTradingVolumeBoost(e.target.value)}
                readOnly={isReadOnly}
                placeholder="0.1"
                className={`w-full rounded-lg border px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors ${isReadOnly ? "border-(--line-subtle) bg-(--bg-surface-secondary) text-(--fg-secondary)" : "border-(--line-subtle) bg-(--bg-input) focus:border-(--line-brand)"}`}
              />
            </div>
            <div>
              <label className="mb-1.5 block text-sm text-(--fg-secondary)">
                {t("points.pnlBoost")}
              </label>
              <input
                type="number"
                value={pnlBoost}
                onChange={e => setPnlBoost(e.target.value)}
                readOnly={isReadOnly}
                placeholder="1"
                className={`w-full rounded-lg border px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors ${isReadOnly ? "border-(--line-subtle) bg-(--bg-surface-secondary) text-(--fg-secondary)" : "border-(--line-subtle) bg-(--bg-input) focus:border-(--line-brand)"}`}
              />
            </div>
          </div>

          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <div>
              <label className="mb-1.5 block text-sm text-(--fg-secondary)">
                {t("points.l1ReferralRate")}
              </label>
              <input
                type="number"
                value={l1ReferralRate}
                onChange={e => setL1ReferralRate(e.target.value)}
                readOnly={isReadOnly}
                placeholder="10"
                className={`w-full rounded-lg border px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors ${isReadOnly ? "border-(--line-subtle) bg-(--bg-surface-secondary) text-(--fg-secondary)" : "border-(--line-subtle) bg-(--bg-input) focus:border-(--line-brand)"}`}
              />
            </div>
            <div>
              <label className="mb-1.5 block text-sm text-(--fg-secondary)">
                {t("points.l2ReferralRate")}
              </label>
              <input
                type="number"
                value={l2ReferralRate}
                onChange={e => setL2ReferralRate(e.target.value)}
                readOnly={isReadOnly}
                placeholder="5"
                className={`w-full rounded-lg border px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors ${isReadOnly ? "border-(--line-subtle) bg-(--bg-surface-secondary) text-(--fg-secondary)" : "border-(--line-subtle) bg-(--bg-input) focus:border-(--line-brand)"}`}
              />
            </div>
          </div>
        </div>

        <div className="mt-6 flex justify-end gap-3">
          <button
            type="button"
            onClick={() => setModalOpen(false)}
            className="rounded-full border border-(--line-strong) bg-transparent px-4 py-2 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
          >
            {isReadOnly ? t("common.close") : t("common.cancel")}
          </button>
          {!isReadOnly && (
            <button
              type="button"
              onClick={handleSaveCampaign}
              disabled={submitting}
              className="rounded-full px-4 py-2 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90 disabled:opacity-50"
              style={{ background: "var(--bg-brand-grad)" }}
            >
              {submitting ? "Saving..." : t("common.save")}
            </button>
          )}
        </div>
      </Modal>
    </PageShell>
  );
}
